#include <stdio.h>
#include <stdlib.h>
#include <time.h>
#include <assert.h>
#include <cuda_runtime.h>

// Inline timer definitions from timer.h
#include <unistd.h>
#include <stdint.h>
#include <stdlib.h>

__inline__ uint64_t rdtsc() 
{
    uint32_t lo, hi;
    __asm__ __volatile__ ("rdtsc" : "=a" (lo), "=d" (hi));
    return (uint64_t)hi << 32 | lo;
}

unsigned long long start_cycles;
#define startCycle() (start_cycles = rdtsc())
#define stopCycle(cycles) (cycles = rdtsc()-start_cycles)

#define pin_stats_reset()   startCycle()
#define pin_stats_pause(cycles)   stopCycle(cycles)
#define pin_stats_dump(cycles)    printf("timer: %Lu\n", cycles)

#define BENCH_PRINT
#define EXIT_SUCCESS 0

int rows, cols;
int* data;
int** wall;
int* result;
#define M_SEED 9

void
init(int argc, char** argv)
{
    if(argc==3){
        cols = atoi(argv[1]);
        rows = atoi(argv[2]);
    }else{
        printf("Usage: pathfiner width num_of_steps\n");
        exit(0);
    }
    data = new int[rows*cols];
    wall = new int*[rows];
    for(int n=0; n<rows; n++)
        wall[n]=data+cols*n;
    result = new int[cols];

    int seed = M_SEED;
    srand(seed);

    for (int i = 0; i < rows; i)
    {
        for (int j = 0; j < cols; j++)
        {
            wall[i][j] = rand() % 10;
        }
    }
    for (int j = 0; j < cols; j++)
        result[j] = wall[0][j];
#ifdef BENCH_PRINT
    for (int i = 0; i < rows; i++)
    {
        for (int j = 0; j < cols; j++)
        {
            printf("%d ",wall[i][j]) ;
        }
        printf("\n") ;
    }
#endif
}

void 
fatal(char *s)
{
    fprintf(stderr, "error: %s\n", s);

}

#define IN_RANGE(x, min, max)   ((x)>= (min) && (x)<=(max))
#define CLAMP_RANGE(x, min, max) x = (x<(min)) ? min : ((x>(max)) ? max : x )
#define MIN(a, b) ((a)<=(b) ? (a) : (b))

__global__ void pathfinder_kernel(int* dst, int* src, int* wall_row, int cols)
{
    int n = blockIdx.x * blockDim.x + threadIdx.x;
    if (n < cols) {
        int min = src[n];
        if (n > 0)
            min = MIN(min, src[n-1]);
        if (n < cols-1)
            min = MIN(min, src[n+1]);
        dst[n] = wall_row[n] + min;
    }
}

int main(int argc, char** argv)
{
    run(argc,argv);

    return EXIT_SUCCESS;
}

void run(int argc, char** argv)
{
    init(argc, argv);

    unsigned long long cycles;

    int *src, *dst, *temp;
    int min;

    dst = result;
    src = new int[cols];

    // CUDA memory allocation
    int *d_src, *d_dst, *d_wall;
    cudaMalloc(&d_src, cols * sizeof(int));
    cudaMalloc(&d_dst, cols * sizeof(int));
    cudaMalloc(&d_wall, rows * cols * sizeof(int));

    // Copy wall data to GPU
    cudaMemcpy(d_wall, data, rows * cols * sizeof(int), cudaMemcpyHostToDevice);

    // Copy initial result to GPU (dst)
    cudaMemcpy(d_dst, result, cols * sizeof(int), cudaMemcpyHostToDevice);

    pin_stats_reset();

    int block_size = 256;
    int num_blocks = (cols + block_size - 1) / block_size;

    for (int t = 0; t < rows-1; t++) {
        temp = src;
        src = dst;
        dst = temp;

        // Copy src to d_src
        cudaMemcpy(d_src, src, cols * sizeof(int), cudaMemcpyHostToDevice);

        // Launch kernel
        pathfinder_kernel<<<num_blocks, block_size>>>(d_dst, d_src, d_wall + (t+1)*cols, cols);

        // Copy result back
        cudaMemcpy(dst, d_dst, cols * sizeof(int), cudaMemcpyDeviceToHost);
    }

    pin_stats_pause(cycles);
    pin_stats_dump(cycles);

#ifdef BENCH_PRINT

    for (int i = 0; i < cols; i++)

            printf("%d ",data[i]) ;

    printf("\n") ;

    for (int i = 0; i < cols; i++)

            printf("%d ",dst[i]) ;

    printf("\n") ;

#endif

    delete [] data;
    delete [] wall;
    delete [] dst;
    delete [] src;

    cudaFree(d_src);
    cudaFree(d_dst);
    cudaFree(d_wall);
}
